var all = $input.all();
var now = new Date().getTime();
var seen = {};
var videos = [];
var dejaAnalyses = [];

// PremiĂ¨re passe â collecte les IDs dĂŠjĂ  analysĂŠs depuis Google Sheets
all.forEach(function(item) {
  var d = item.json;
  if (d.videoId && !d.contentDetails && !d.snippet) {
    dejaAnalyses.push(d.videoId);
  }
});

// DeuxiĂ¨me passe â traite les items YouTube
all.forEach(function(item) {
  var d = item.json;

  // Ignore les lignes Google Sheets
  if (d.videoId && !d.contentDetails && !d.snippet) return;

  var videoId = d.contentDetails && d.contentDetails.videoId
    ? d.contentDetails.videoId
    : null;

  if (!videoId) return;
  if (seen[videoId] || dejaAnalyses.includes(videoId)) return;
  seen[videoId] = true;

  var title       = (d.snippet && d.snippet.title) || '';
  var description = ((d.snippet && d.snippet.description) || '').slice(0, 500);
  var publishedAt = (d.snippet && d.snippet.publishedAt)
    || (d.contentDetails && d.contentDetails.videoPublishedAt) || '';

  var titleLower = title.toLowerCase();
  var sujet = 'autre';
  if (titleLower.match(/\b(ia|ai|gpt|llm|claude|gemini|mistral|agent|deepseek|machine learning|intelligence artificielle|automation|automatisation)\b/)) {
    sujet = 'IA';
  } else if (titleLower.match(/\b(seo|rĂŠfĂŠrencement|google|search|serp|backlink|keyword|mot.clĂŠ|netlinking|contenu|content)\b/)) {
    sujet = 'SEO';
  }

  var videoDate = publishedAt ? new Date(publishedAt).getTime() : 0;
  var ageJours  = videoDate ? Math.floor((now - videoDate) / (1000 * 60 * 60 * 24)) : 999;

  var poidsDate;
  if (ageJours <= 7)        poidsDate = 5;
  else if (ageJours <= 30)  poidsDate = 4;
  else if (ageJours <= 90)  poidsDate = 3;
  else if (ageJours <= 180) poidsDate = 2;
  else if (ageJours <= 365) poidsDate = 1;
  else                      poidsDate = 0;

  var poidsSujet = (sujet === 'IA' || sujet === 'SEO') ? 2 : 0;
  var scoreInitial = poidsDate + poidsSujet;

  videos.push({
    videoId:      videoId,
    title:        title,
    description:  description,
    sujet:        sujet,
    ageJours:     ageJours,
    publishedAt:  publishedAt,
    scoreInitial: scoreInitial,
    url:          'https://youtube.com/watch?v=' + videoId
  });
});

videos.sort(function(a, b) { return b.scoreInitial - a.scoreInitial; });
videos = videos.slice(0, 70);

return videos.map(function(v) { return { json: v }; });

